<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('support.manage');$ticketId=(int)vp3_input('id');if(vp3_method()==='POST'){vp3_verify_csrf();$action=vp3_input('action','status');if($action==='reply'&&$ticketId){$message=vp3_input('message');if(strlen($message)>=2){vp3_db()->prepare("INSERT INTO support_ticket_messages(ticket_id,sender_type,sender_id,message,created_at) VALUES(?,'admin',?,?,NOW())")->execute([$ticketId,$admin['id'],$message]);vp3_db()->prepare("UPDATE support_tickets SET ticket_status='waiting_customer',updated_at=NOW() WHERE id=?")->execute([$ticketId]);vp3_audit('admin',(int)$admin['id'],'support.replied','support_ticket',(string)$ticketId);}}else{$id=(int)vp3_input('id');$status=vp3_input('ticket_status');if(in_array($status,['open','in_progress','waiting_customer','resolved','closed'],true)){vp3_db()->prepare("UPDATE support_tickets SET ticket_status=?,closed_at=IF(?='closed',NOW(),closed_at),updated_at=NOW() WHERE id=?")->execute([$status,$status,$id]);vp3_audit('admin',(int)$admin['id'],'support.status_updated','support_ticket',(string)$id,['status'=>$status]);}}vp3_redirect('admin/support.php'.($ticketId?'?id='.$ticketId:''));}$pageTitle='Support Tickets';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT t.*,c.name customer_name FROM support_tickets t JOIN customers c ON c.id=t.customer_id ORDER BY t.id DESC LIMIT 250')->fetchAll();$ticket=null;$messages=[];if($ticketId){$stmt=vp3_db()->prepare('SELECT t.*,c.name customer_name,c.email FROM support_tickets t JOIN customers c ON c.id=t.customer_id WHERE t.id=?');$stmt->execute([$ticketId]);$ticket=$stmt->fetch();if(is_array($ticket)){$stmt=vp3_db()->prepare('SELECT sender_type,sender_id,message,created_at FROM support_ticket_messages WHERE ticket_id=? ORDER BY id');$stmt->execute([$ticketId]);$messages=$stmt->fetchAll();}}?><h1>Support tickets</h1><div class="table-wrap"><table class="table"><thead><tr><th>Ticket</th><th>Customer</th><th>Subject</th><th>Priority</th><th>Status</th><th>Update</th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><a href="support.php?id=<?=(int)$x['id']?>"><?=vp3_e($x['ticket_number'])?></a></td><td><?=vp3_e($x['customer_name'])?></td><td><?=vp3_e($x['subject'])?></td><td><?=vp3_e($x['priority'])?></td><td><?=vp3_e($x['ticket_status'])?></td><td><form method="post" class="hero-actions"><?=vp3_csrf_field()?><input type="hidden" name="id" value="<?=(int)$x['id']?>"><input type="hidden" name="action" value="status"><select name="ticket_status"><?php foreach(['open','in_progress','waiting_customer','resolved','closed'] as $st):?><option <?=$x['ticket_status']===$st?'selected':''?>><?=$st?></option><?php endforeach;?></select><button class="button small">Save</button></form></td></tr><?php endforeach;?></tbody></table></div><?php if(is_array($ticket)):?><section class="card"><h2><?=vp3_e($ticket['ticket_number'].' · '.$ticket['customer_name'])?></h2><p><?=vp3_e($ticket['email'].' · '.$ticket['subject'])?></p><?php foreach($messages as $m):?><article class="card"><strong><?=vp3_e(ucfirst($m['sender_type']))?></strong><small> · <?=vp3_e($m['created_at'])?></small><p><?=nl2br(vp3_e($m['message']))?></p></article><?php endforeach;?><?php if($ticket['ticket_status']!=='closed'):?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="reply"><input type="hidden" name="id" value="<?=$ticketId?>"><div class="field"><label>Reply</label><textarea name="message" required></textarea></div><button class="button">Send reply</button></form><?php endif;?></section><?php endif;?><?php require VP3_ROOT.'/includes/admin-footer.php';?>
